// ============================================================
// Extrai dados do evento a partir do corpo do e-mail
//
// Formato esperado (enviar para o email do portal):
//
// Assunto: Evento: Nome do Evento
//
// EVENTO: Corrida 5K Parque da Redenção
// DATA: 29/03/2026
// LOCAL: Parque da Redenção
// CIDADE: Porto Alegre
// ESPORTE: Corrida
// ORGANIZADOR: Associação RS Running
// CONTATO: (51) 99999-9999
// GRATUITO: sim
// LINK: https://sympla.com.br/...
// DESCRICAO: Texto livre sobre o evento...
// ============================================================

const body = $json.text || ($json.html || '').replace(/<[^>]+>/g, '');
const subject = $json.subject || '';

const extract = (label) => {
  const m = body.match(new RegExp(`${label}:\\s*(.+)`, 'i'));
  return m ? m[1].trim() : null;
};

const parseDate = (str) => {
  if (!str) return null;
  const m = str.match(/(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})/);
  return m ? `${m[3]}-${m[2].padStart(2,'0')}-${m[1].padStart(2,'0')}` : null;
};

const esporteMap = {
  'futebol': 'futebol', 'futsal': 'futsal',
  'volei': 'volei', 'vôlei': 'volei',
  'basquete': 'basquete', 'atletismo': 'atletismo',
  'corrida': 'corrida-de-rua', 'natacao': 'natacao', 'natação': 'natacao',
  'judo': 'judo', 'judô': 'judo', 'karate': 'karate', 'karatê': 'karate',
  'ciclismo': 'ciclismo', 'handebol': 'handebol',
  'tenis': 'tenis', 'tênis': 'tenis', 'padel': 'padel', 'rugby': 'rugby'
};

const esporteRaw = (extract('ESPORTE') || '').toLowerCase();
const esporte_slug = Object.entries(esporteMap).find(([k]) => esporteRaw.includes(k))?.[1] || null;

const data_inicio = parseDate(extract('DATA'));

if (!data_inicio) {
  console.log('⚠️ Data não encontrada no e-mail:', extract('DATA'));
  return [];
}

const titulo = extract('EVENTO') || subject.replace(/evento[:\s]*/i, '').trim();

if (!titulo) {
  console.log('⚠️ Título do evento não encontrado');
  return [];
}

return [{ json: {
  titulo,
  data_inicio,
  local_nome: extract('LOCAL') || 'A confirmar',
  local_cidade: extract('CIDADE') || 'Porto Alegre',
  organizador_nome: extract('ORGANIZADOR') || ($json.from?.split('<')[0].trim()) || 'Não informado',
  organizador_contato: extract('CONTATO') || $json.from || null,
  esporte_slug,
  gratuito: !(extract('GRATUITO') || 'sim').toLowerCase().includes('não'),
  url_inscricao: extract('LINK') || null,
  descricao: extract('DESCRICAO') || null
}}];

const response = $input.item.json;
const titulo = $('🔍 Extrair dados do evento').item.json.titulo;

if (response.success) {
  console.log(`✅ Evento cadastrado: ${titulo}`);
} else {
  console.log(`❌ Erro: ${titulo} — ${JSON.stringify(response)}`);
}

return $input.all();
